import React, { useEffect, useMemo, useRef, useState } from 'react'
import { PUZZLES } from './data/puzzles.js'
import {
  areAdjacent,
  canonicalBridgeKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory,
  parseBridgeKey,
} from './utils/hashiLogic.js'

const UNIT = 40
const W = 800
const H = 600

function islandPixel(isl) {
  return { px: isl.x * UNIT, py: isl.y * UNIT }
}

function findIslandById(islands, id) {
  return islands.find((i) => i.id === id) || null
}

function findNearestInDirection(islands, from, dx, dy) {
  // Move to the closest island in a cardinal direction.
  let best = null
  let bestDist = Infinity
  for (const isl of islands) {
    if (isl.id === from.id) continue
    const vx = isl.x - from.x
    const vy = isl.y - from.y
    if (dx !== 0) {
      if (vy !== 0) continue
      if (Math.sign(vx) !== dx) continue
      const d = Math.abs(vx)
      if (d < bestDist) {
        bestDist = d
        best = isl
      }
    } else if (dy !== 0) {
      if (vx !== 0) continue
      if (Math.sign(vy) !== dy) continue
      const d = Math.abs(vy)
      if (d < bestDist) {
        bestDist = d
        best = isl
      }
    }
  }
  return best
}

function bridgeCenterPixels(key) {
  const { x1, y1, x2, y2 } = parseBridgeKey(key)
  const cx = ((x1 + x2) / 2) * UNIT
  const cy = ((y1 + y2) / 2) * UNIT
  return { cx, cy }
}

export default function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0)
  const islands = useMemo(() => PUZZLES[puzzleIndex].islands, [puzzleIndex])

  const [bridges, setBridges] = useState(() => new Map())
  const [selectedIslandId, setSelectedIslandId] = useState(null)
  const [cursorIslandId, setCursorIslandId] = useState(islands[0]?.id || null)
  const [error, setError] = useState(null)

  const svgRef = useRef(null)

  useEffect(() => {
