        e.key === 'ArrowRight' ? [1, 0] :
        e.key === 'ArrowUp' ? [0, -1] :
        e.key === 'ArrowDown' ? [0, 1] :
        null

      if (dir) {
        e.preventDefault()
        const [dx, dy] = dir
        const nxt = findNearestInDirection(islands, cur, dx, dy)
        if (nxt) setCursorIslandId(nxt.id)
        return
      }

      if (e.key === 'Enter') {
        e.preventDefault()
        const cursorIsland = findIslandById(islands, cursorIslandId)
        if (!cursorIsland) return

        if (!selectedIslandId) {
          setSelectedIslandId(cursorIsland.id)
          clearErrorOnValidMove()
          return
        }

        if (selectedIslandId === cursorIsland.id) {
          // Do nothing
          clearErrorOnValidMove()
          return
        }

        const from = findIslandById(islands, selectedIslandId)
        const to = cursorIsland
        cycleBridge(from, to)
        setSelectedIslandId(null)
      }
    }

    window.addEventListener('keydown', onKeyDown)
    return () => window.removeEventListener('keydown', onKeyDown)
