}

function bridgeCenterPixels(key) {
  const { x1, y1, x2, y2 } = parseBridgeKey(key)
  const cx = ((x1 + x2) / 2) * UNIT
  const cy = ((y1 + y2) / 2) * UNIT
  return { cx, cy }
}

export default function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0)
  const islands = useMemo(() => PUZZLES[puzzleIndex].islands, [puzzleIndex])

  const [bridges, setBridges] = useState(() => new Map())
  const [selectedIslandId, setSelectedIslandId] = useState(null)
  const [cursorIslandId, setCursorIslandId] = useState(islands[0]?.id || null)
  const [error, setError] = useState(null)

  const svgRef = useRef(null)

  useEffect(() => {
    // When puzzle changes: fully reset.
    setBridges(new Map())
    setSelectedIslandId(null)
    setError(null)
    setCursorIslandId(PUZZLES[puzzleIndex].islands[0]?.id || null)
  }, [puzzleIndex])

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges])
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges])

  function clearErrorOnValidMove() {
    if (error) setError(null)
  }

  function applyBridgeDelta(from, to, delta) {
    const res = canAddBridge(islands, bridges, from, to, delta)
    if (!res.valid) {
      setError(res.error)
      return
    }

    setBridges((prev) => {
      const next = new Map(prev)
      const key = canonicalBridgeKey(from, to)
      const cur = next.get(key) || 0
      const n = cur + delta
      if (n <= 0) next.delete(key)
      else next.set(key, n)
      return next
    })

    clearErrorOnValidMove()
  }

  function cycleBridge(from, to) {
    if (!areAdjacent(islands, from, to)) {
      setError('Cannot connect non-adjacent islands')
      return
    }

    const key = canonicalBridgeKey(from, to)
    const cur = bridges.get(key) || 0
    const target = cur === 0 ? 1 : cur === 1 ? 2 : 0
    const delta = target - cur

    if (delta === 0) {
      clearErrorOnValidMove()
      return
    }

    applyBridgeDelta(from, to, delta)
  }

  function onIslandClick(isl, evt) {
    evt.preventDefault()
    if (!selectedIslandId) {
      setSelectedIslandId(isl.id)
      setCursorIslandId(isl.id)
      clearErrorOnValidMove()
      return
    }

    if (selectedIslandId === isl.id) {
      // Keep selected; no toggle on same island.
      setCursorIslandId(isl.id)
      clearErrorOnValidMove()
      return
    }

    const from = findIslandById(islands, selectedIslandId)
    const to = isl
    cycleBridge(from, to)
    setSelectedIslandId(null)
    setCursorIslandId(isl.id)
  }

  function onReset() {
    setBridges(new Map())
    setSelectedIslandId(null)
    setError(null)
  }

  function toggleBridgeAtKey(key, evt) {
    evt.preventDefault()
    const cur = bridges.get(key) || 0
    const target = cur === 0 ? 1 : cur === 1 ? 2 : 0
    const delta = target - cur
    const { x1, y1, x2, y2 } = parseBridgeKey(key)
    const from = { x: x1, y: y1 }
    const to = { x: x2, y: y2 }
    if (delta === 0) {
      clearErrorOnValidMove()
      return
    }
    applyBridgeDelta(from, to, delta)
  }

  useEffect(() => {
    const el = svgRef.current
    if (!el) return

    function onKeyDown(e) {
      const cur = findIslandById(islands, cursorIslandId) || islands[0]
      if (!cur) return

      if (e.key === 'Escape') {
        setSelectedIslandId(null)
        clearErrorOnValidMove()
        return
      }

      const dir =
        e.key === 'ArrowLeft' ? [-1, 0] :
        e.key === 'ArrowRight' ? [1, 0] :
        e.key === 'ArrowUp' ? [0, -1] :
        e.key === 'ArrowDown' ? [0, 1] :
        null

      if (dir) {
        e.preventDefault()
        const [dx, dy] = dir
        const nxt = findNearestInDirection(islands, cur, dx, dy)
        if (nxt) setCursorIslandId(nxt.id)
        return
      }

      if (e.key === 'Enter') {
        e.preventDefault()
        const cursorIsland = findIslandById(islands, cursorIslandId)
        if (!cursorIsland) return

        if (!selectedIslandId) {
          setSelectedIslandId(cursorIsland.id)
          clearErrorOnValidMove()
          return
        }

        if (selectedIslandId === cursorIsland.id) {
          // Do nothing
          clearErrorOnValidMove()
          return
        }

        const from = findIslandById(islands, selectedIslandId)
        const to = cursorIsland
        cycleBridge(from, to)
        setSelectedIslandId(null)
      }
    }

    window.addEventListener('keydown', onKeyDown)
    return () => window.removeEventListener('keydown', onKeyDown)
  }, [cursorIslandId, islands, selectedIslandId, bridges, error])

  const cursorIsland = findIslandById(islands, cursorIslandId)
  const selectedIsland = findIslandById(islands, selectedIslandId)

  return (
    <div className="app">
      <div className="hud">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIndex}
            onChange={(e) => setPuzzleIndex(Number(e.target.value))}
          >
            {PUZZLES.map((p, idx) => (
              <option key={p.label} value={idx}>{p.label}</option>
            ))}
          </select>
        </label>
        <button onClick={onReset}>Reset</button>
        <div>
          {selectedIsland ? `Selected: ${selectedIsland.id.toUpperCase()}` : 'Selected: (none)'}
        </div>
      </div>

      {victory && <div className="victory-banner">SOLVED!</div>}
      {error && <div className="error-message">{error}</div>}

      <svg
        ref={svgRef}
        width={W}
        height={H}
        viewBox={`0 0 ${W} ${H}`}
        onContextMenu={(e) => e.preventDefault()}
      >
        {/* Bridges */}
        {[...bridges.entries()].map(([key, num]) => {
          if (!num) return null
          const { x1, y1, x2, y2 } = parseBridgeKey(key)
          const p1 = { x: x1 * UNIT, y: y1 * UNIT }
          const p2 = { x: x2 * UNIT, y: y2 * UNIT }

          const isVert = p1.x === p2.x
          const offset = 5
          const stroke = 'rgba(0,255,102,0.9)'
          const common = {
            stroke,
            strokeWidth: 3,
            strokeLinecap: 'round',
          }

          const lines = []
          if (num === 1) {
            lines.push(
              <line
                key={`${key}-1`}
                x1={p1.x}
                y1={p1.y}
                x2={p2.x}
                y2={p2.y}
                {...common}
              />
            )
          } else {
            if (isVert) {
              lines.push(
                <line key={`${key}-a`} x1={p1.x - offset} y1={p1.y} x2={p2.x - offset} y2={p2.y} {...common} />,
                <line key={`${key}-b`} x1={p1.x + offset} y1={p1.y} x2={p2.x + offset} y2={p2.y} {...common} />
              )
            } else {
              lines.push(
                <line key={`${key}-a`} x1={p1.x} y1={p1.y - offset} x2={p2.x} y2={p2.y - offset} {...common} />,
                <line key={`${key}-b`} x1={p1.x} y1={p1.y + offset} x2={p2.x} y2={p2.y + offset} {...common} />
              )
            }
          }

          // Invisible, fat hit target for right-click / ctrl-click toggling.
          const { cx, cy } = bridgeCenterPixels(key)

          return (
            <g key={key}>
              {lines}
              <line
                x1={p1.x}
                y1={p1.y}
                x2={p2.x}
                y2={p2.y}
                stroke="transparent"
                strokeWidth={18}
                onMouseDown={(e) => {
                  if (e.button === 2 || e.ctrlKey) toggleBridgeAtKey(key, e)
                }}
                onContextMenu={(e) => toggleBridgeAtKey(key, e)}
              />
              <text x={cx + 8} y={cy - 8} fill="rgba(0,255,102,0.35)" fontSize="10">{num}</text>
            </g>
          )
        })}

        {/* Cursor (must not be circle) */}
        {cursorIsland && (() => {
          const { px, py } = islandPixel(cursorIsland)
          return (
            <rect
              x={px - 18}
              y={py - 18}
              width={36}
              height={36}
              fill="none"
              stroke="rgba(0,255,102,0.95)"
              strokeWidth={2}
              strokeDasharray="4 3"
            />
          )
        })()}

        {/* Islands */}
        {islands.map((isl) => {
          const { px, py } = islandPixel(isl)
          const curCount = counts.get(isl.id) || 0
          const isSelected = isl.id === selectedIslandId
          const satisfied = curCount === isl.value

          return (
            <g key={isl.id} onMouseDown={(e) => onIslandClick(isl, e)} style={{ cursor: 'pointer' }}>
              <circle
                cx={px}
                cy={py}
                r={14}
                fill="#000"
                stroke={isSelected ? '#00ff66' : satisfied ? 'rgba(0,255,102,0.8)' : 'rgba(0,255,102,0.5)'}
                strokeWidth={isSelected ? 3 : 2}
              />
              <text
                x={px}
                y={py + 5}
                textAnchor="middle"
                fontSize="14"
                fill="#00ff66"
              >
                {isl.value}
              </text>
            </g>
          )
        })}
      </svg>
    </div>
  )
}
